SELECT DISTINCT 'Games Played' AS category, `player`.`name_given`, `batting`.`g` AS value FROM `batting` JOIN `player` ON `batting`.`player_id` = `player`.`player_id` WHERE `batting`.`g` = (SELECT MAX(`g`) FROM `batting`) UNION ALL SELECT DISTINCT 'Runs' AS category, `player`.`name_given`, `batting`.`r` AS value FROM `batting` JOIN `player` ON `batting`.`player_id` = `player`.`player_id` WHERE `batting`.`r` = (SELECT MAX(`r`) FROM `batting`) UNION ALL SELECT DISTINCT 'Hits' AS category, `player`.`name_given`, `batting`.`h` AS value FROM `batting` JOIN `player` ON `batting`.`player_id` = `player`.`player_id` WHERE `batting`.`h` = (SELECT MAX(`h`) FROM `batting`) UNION ALL SELECT DISTINCT 'Home Runs' AS category, `player`.`name_given`, `batting`.`hr` AS value FROM `batting` JOIN `player` ON `batting`.`player_id` = `player`.`player_id` WHERE `batting`.`hr` = (SELECT MAX(`hr`) FROM `batting`)